import React from 'react';
import './Button.css';
import { BrowserRouter as Router, Link} from 'react-router-dom';
import Contact from '../../pages/Contact/Contact';

function ContactButton() {

    function changeBackground(e) {
        e.target.style.background = '#045164ea';
        e.target.style.color='white';
    }

    function changeBack(e) {
        e.target.style.background = 'transparent';
        e.target.style.color='#08fdd8';
    }

  return (
    <Router basename={process.env.PUBLIC_URL}>
        
        <Link to='/contact' component={Contact} className="contact-button" 
        onMouseOver={changeBackground}
        onMouseLeave={changeBack}>Contact me!</Link>
    </Router> 
    // {/* <a className="contact-button" href={process.env.PUBLIC_URL + '/contact'}
    //   onMouseOver={changeBackground}
    //   onMouseLeave={changeBack}>Contact me!
    // </a> */}
  );
}

export default ContactButton;


